export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type Customer = {
  yearsWithMHPCO: number;
};

export type Damage = {
  itemType: string;
  amount: number;
};

export type Incident = {
  cause: string;
  damages: Damage[];
};

export type QuoteStep = {
  op: 'quote';
  items: Item[];
};

export type ClaimStep = {
  op: 'claim';
  policy: number;
  incident: Incident;
};

export type Step = QuoteStep | ClaimStep;

export type Scenario = {
  customer: Customer;
  steps: Step[];
};

export type QuoteResult = { premium: number };
export type ClaimResult = { payout: number; remainingCap: number };
export type StepResult = QuoteResult | ClaimResult;

type MainItemSpec = { insuranceValue: number; basePremium: number };

const MAIN_ITEMS: Record<string, MainItemSpec> = {
  sword: { insuranceValue: 1000, basePremium: 100 },
  amulet: { insuranceValue: 600, basePremium: 60 },
  staff: { insuranceValue: 800, basePremium: 80 },
  potion: { insuranceValue: 400, basePremium: 40 },
};

const COMPONENT_TYPES = new Set(['rune', 'moonstone']);
const COMPONENT_INSURANCE_VALUE = 250;
const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const DEDUCTIBLE = 100;
const PROCESSING_FEE = 5;

function isComponent(type: string): boolean {
  return COMPONENT_TYPES.has(type);
}

function isKnownType(type: string): boolean {
  return type in MAIN_ITEMS || isComponent(type);
}

function itemInsuranceValue(item: Item): number {
  if (item.type in MAIN_ITEMS) return MAIN_ITEMS[item.type].insuranceValue;
  if (isComponent(item.type)) return COMPONENT_INSURANCE_VALUE;
  throw new Error(`Unknown item type: ${item.type}`);
}

function itemBasePremium(item: Item): number {
  if (item.type in MAIN_ITEMS) return MAIN_ITEMS[item.type].basePremium;
  if (isComponent(item.type)) return COMPONENT_BASE_PREMIUM;
  throw new Error(`Unknown item type: ${item.type}`);
}

function componentBlockPremium(count: number): number {
  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
  const remainder = count % COMPONENT_BLOCK_SIZE;
  return blocks * COMPONENT_BLOCK_PREMIUM + remainder * COMPONENT_BASE_PREMIUM;
}

function itemPremiumWithItemModifiers(item: Item, basePremium: number): number {
  let premium = basePremium;
  if (item.cursed) premium += basePremium * 0.5;
  if ((item.enchantment ?? 0) >= 5) premium += basePremium * 0.3;
  return premium;
}

function policyBasePremium(items: Item[]): number {
  // Validate types
  for (const item of items) {
    if (!isKnownType(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }

  // Group components by type for block discount
  const componentCounts = new Map<string, number>();
  let total = 0;

  for (const item of items) {
    if (isComponent(item.type)) {
      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
    } else {
      // Main item: base + item modifiers
      const base = itemBasePremium(item);
      total += itemPremiumWithItemModifiers(item, base);
    }
  }

  // Components: use block discount on base premium then apply item modifiers per group
  // Per spec, components mentioned in examples don't have enchantment/cursed; treat
  // each component as plain — block discount applies to the base premium of the group.
  for (const [, count] of componentCounts) {
    total += componentBlockPremium(count);
  }

  return total;
}

export function quotePremium(
  items: Item[],
  customer: Customer,
  contractIndex: number, // 0 = first contract for the customer
): number {
  // Validate
  for (const item of items) {
    if (!isKnownType(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }

  const policyBase = policyBasePremium(items);

  let premium = policyBase;

  // Policy-wide modifiers
  if (customer.yearsWithMHPCO >= 2) {
    premium -= policyBase * 0.2;
  }
  // First insurance: per spec confirmed in long-standing customer example,
  // "each item in a quote is treated as a first insurance" — so it always applies
  // to every item in the quote. The surcharge is 10% of each item's base premium.
  let firstInsuranceSurcharge = 0;
  // Group components for first-insurance calc using block discount base
  const componentCounts = new Map<string, number>();
  for (const item of items) {
    if (isComponent(item.type)) {
      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
    } else {
      firstInsuranceSurcharge += itemBasePremium(item) * 0.1;
    }
  }
  for (const [, count] of componentCounts) {
    firstInsuranceSurcharge += componentBlockPremium(count) * 0.1;
  }
  premium += firstInsuranceSurcharge;

  // Follow-up contract discount (contractIndex >= 1)
  if (contractIndex >= 1) {
    premium -= policyBase * 0.15;
  }

  premium += PROCESSING_FEE;

  return Math.ceil(premium);
}

export type Policy = {
  items: Item[];
  insuranceSum: number;
  cap: number;
  remainingCap: number;
};

export function createPolicy(items: Item[]): Policy {
  const insuranceSum = items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
  const cap = insuranceSum * 2;
  return { items: [...items], insuranceSum, cap, remainingCap: cap };
}

function findItemForDamage(policy: Policy, itemType: string, usedIndices: Set<number>): number {
  for (let i = 0; i < policy.items.length; i++) {
    if (usedIndices.has(i)) continue;
    if (policy.items[i].type === itemType) return i;
  }
  return -1;
}

function rawPayoutForDamage(item: Item, damageAmount: number): number {
  let reimbursable = damageAmount;
  const isDragon = item.material === 'dragon';
  const isHighEnchant = (item.enchantment ?? 0) >= 8;

  if (isDragon) {
    reimbursable = damageAmount; // full
  } else if (isHighEnchant) {
    reimbursable = damageAmount * 0.5;
  }
  return reimbursable;
}

export function processClaim(policy: Policy, incident: Incident): number {
  // Validate amounts
  for (const dmg of incident.damages) {
    if (dmg.amount < 0) {
      throw new Error(`Negative damage amount: ${dmg.amount}`);
    }
  }

  // Validate item types are known
  for (const dmg of incident.damages) {
    if (!isKnownType(dmg.itemType)) {
      throw new Error(`Unknown item type in claim: ${dmg.itemType}`);
    }
  }

  // Match each damage entry to a policy item (each entry consumes one item instance)
  const usedIndices = new Set<number>();
  const matched: Array<{ item: Item; amount: number }> = [];

  for (const dmg of incident.damages) {
    const idx = findItemForDamage(policy, dmg.itemType, usedIndices);
    if (idx === -1) {
      throw new Error(`Damage references item not in policy: ${dmg.itemType}`);
    }
    usedIndices.add(idx);
    matched.push({ item: policy.items[idx], amount: dmg.amount });
  }

  // Compute payouts; cap accumulates across damages within this claim
  let totalPayout = 0;
  for (const { item, amount } of matched) {
    const reimbursable = rawPayoutForDamage(item, amount);
    const afterDeductible = Math.max(0, reimbursable - DEDUCTIBLE);
    totalPayout += afterDeductible;
  }

  // Round down (in MHPCO's favor)
  let finalPayout = Math.floor(totalPayout);

  // Apply cap
  if (finalPayout > policy.remainingCap) {
    finalPayout = policy.remainingCap;
  }

  policy.remainingCap -= finalPayout;
  return finalPayout;
}

export function runScenario(scenario: Scenario): { results: StepResult[] } {
  const results: StepResult[] = [];
  const policies = new Map<number, Policy>();
  let quoteCount = 0;

  for (let i = 0; i < scenario.steps.length; i++) {
    const step = scenario.steps[i];
    if (step.op === 'quote') {
      const premium = quotePremium(step.items, scenario.customer, quoteCount);
      const policy = createPolicy(step.items);
      policies.set(i, policy);
      results.push({ premium });
      quoteCount++;
    } else {
      const policy = policies.get(step.policy);
      if (!policy) {
        throw new Error(`Claim references unknown policy index: ${step.policy}`);
      }
      const payout = processClaim(policy, step.incident);
      results.push({ payout, remainingCap: policy.remainingCap });
    }
  }

  return { results };
}

