  let totalPayout = 0;
  for (const { item, amount } of matched) {
    const reimbursable = rawReimbursementForDamage(item, amount);
    const afterDeductible = Math.max(0, reimbursable - DEDUCTIBLE);
    totalPayout += afterDeductible;
  }

  let finalPayout = Math.floor(totalPayout);
  if (finalPayout > policy.remainingCap) {
    finalPayout = policy.remainingCap;
  }

  policy.remainingCap -= finalPayout;
  return finalPayout;
